// Valider la transition de statut selon le workflow défini
const body = $input.first().json.body || $input.first().json;

const { complaintId, nouveauStatut, ancienStatut, userId, commentaire, justification } = body;

// Matrice des transitions autorisées
const transitionsAutorisees = {
  'Nouvelle':   ['Assignée', 'Rejetée'],
  'Assignée':   ['En cours', 'Rejetée'],
  'En cours':   ['Validation', 'Assignée', 'Rejetée'],
  'Validation': ['Clôturée', 'En cours', 'Rejetée'],
  'Rejetée':    [],
  'Clôturée':   [],
  'Escaladée':  ['En cours', 'Validation', 'Clôturée']
};

const transitionsOK = transitionsAutorisees[ancienStatut] || [];

if (!transitionsOK.includes(nouveauStatut)) {
  throw new Error(`Transition non autorisée: ${ancienStatut} → ${nouveauStatut}. Transitions possibles: ${transitionsOK.join(', ')}`);
}

if (!complaintId || !nouveauStatut || !ancienStatut || !userId) {
  throw new Error('Paramètres manquants: complaintId, nouveauStatut, ancienStatut, userId sont requis');
}

if (nouveauStatut === 'Rejetée' && !justification) {
  throw new Error('Une justification est obligatoire pour rejeter une réclamation');
}

const maintenant = new Date().toISOString();

return [{
  json: {
    complaintId: parseInt(complaintId),
    nouveauStatut,
    ancienStatut,
    userId: parseInt(userId),
    commentaire: commentaire || '',
    justification: justification || '',
    dateChangement: maintenant,
    estCloture: nouveauStatut === 'Clôturée',
    estRejetee: nouveauStatut === 'Rejetée',
    estValidation: nouveauStatut === 'Validation',
    estEnCours: nouveauStatut === 'En cours'
  }
}];

